const jobId = $('Extract Fields').item.json.job_id;
const scriptText = $('Extract Fields').item.json.script_text;
const channelId = $('Extract Fields').item.json.channel_id;
const userId = $('Extract Fields').item.json.user_id;
const autoTrigger = !!$('Extract Fields').item.json.auto_trigger_wf12;

function classifyTtsError(detail, statusCode) {
  const normalized = String(detail || '').toLowerCase();
  const runtimeMarkers = [
    'averaged_perceptron_tagger_eng',
    "resource '",
    'nltk',
    'traceback',
    '"exception":"',
    'searched in:',
  ];
  const requestMarkers = [
    'script_text is required',
    'ref_audio_path is required',
    'prompt_text cannot be empty',
    'tts_ref_audio_path와 tts_prompt_text는 함께 설정해야 합니다.',
    'invalid',
    'unprocessable',
  ];

  if (runtimeMarkers.some((marker) => normalized.includes(marker))) {
    return 'tts_server_runtime_error';
  }
  if (requestMarkers.some((marker) => normalized.includes(marker))) {
    return 'request_validation_error';
  }
  if (statusCode >= 500) {
    return 'tts_server_runtime_error';
  }
  if ([400, 401, 403, 404, 405, 409, 422].includes(statusCode)) {
    return 'request_validation_error';
  }
  return 'tts_server_runtime_error';
}

if (!scriptText || !scriptText.trim()) {
  return {
    json: {
      ok: false,
      error_type: 'request_validation_error',
      error: 'script_text is required',
      job_id: jobId,
      channel_id: channelId,
      user_id: userId,
    },
  };
}

try {
  const ttsApiUrl = ($env.TTS_API_URL || '').trim();
  if (!ttsApiUrl) {
    throw new Error('TTS_API_URL is not configured');
  }

  const ttsBody = {
    text: scriptText,
    text_lang: $env.TTS_TEXT_LANG || 'ko',
    prompt_lang: $env.TTS_PROMPT_LANG || $env.TTS_TEXT_LANG || 'ko',
    media_type: 'wav',
    streaming_mode: false,
    top_k: Number($env.TTS_TOP_K || 20),
    sample_steps: Number($env.TTS_SAMPLE_STEPS || 32),
    super_sampling: ['1', 'true', 'yes', 'on'].includes(String($env.TTS_SUPER_SAMPLING || 'true').trim().toLowerCase()),
    fragment_interval: Number($env.TTS_FRAGMENT_INTERVAL || 0.4),
  };

  const refAudioPath = ($env.TTS_REF_AUDIO_PATH || '').trim();
  const promptText = ($env.TTS_PROMPT_TEXT || '').trim();
  if (refAudioPath || promptText) {
    if (!(refAudioPath && promptText)) {
      throw new Error('TTS_REF_AUDIO_PATH와 TTS_PROMPT_TEXT는 함께 설정해야 합니다.');
    }
    ttsBody.ref_audio_path = refAudioPath;
    ttsBody.prompt_text = promptText;
  }

  const endpoint = ttsApiUrl.endsWith('/tts') ? ttsApiUrl : `${ttsApiUrl}/tts`;
  const ttsResp = await fetch(endpoint, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(ttsBody),
  });

  if (!ttsResp.ok) {
    const responseText = await ttsResp.text();
    const errorType = classifyTtsError(responseText, ttsResp.status);
    throw new Error(`TTS API failed [${errorType}]: ${ttsResp.status} ${responseText}`);
  }

  const audioBuffer = await ttsResp.arrayBuffer();
  const audioBytes = Buffer.from(audioBuffer);
  const audioB64 = audioBytes.toString('base64');

  const kstDate = new Intl.DateTimeFormat('en-CA', {
    timeZone: 'Asia/Seoul',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).format(new Date()).replace(/-/g, '');
  const filename = `${kstDate}-${jobId}.wav`;

  return {
    json: {
      ok: true,
      job_id: jobId,
      channel_id: channelId,
      user_id: userId,
      script_text: scriptText,
      audio_file_path: '',
      filename,
      audio_content_b64: audioB64,
      auto_trigger_wf12: autoTrigger,
    },
  };
} catch (e) {
  const message = e && e.message ? e.message : String(e);
  const match = message.match(/\[(request_validation_error|tts_server_runtime_error)\]/);
  return {
    json: {
      ok: false,
      error_type: match ? match[1] : classifyTtsError(message, 0),
      error: message,
      job_id: jobId,
      channel_id: channelId,
      user_id: userId,
    },
  };
}
